        if self.destination == 'domestic':
            return self._calculate_cost(self.DOMESTIC_RATES, self.DOMESTIC_EXTRA_COST)
        elif self.destination == 'international':
            return self._calculate_cost(self.INTERNATIONAL_RATES, self.INTERNATIONAL_EXTRA_COST)
        else:
