class ShippingCalculator:
    DOMESTIC_RATES = [
        (1, 5.99),
        (5, 8.99),
        (20, 12.99),
        (float('inf'), 12.99)  # Additional charge for weight over 20 is handled separately
    ]

    INTERNATIONAL_RATES = [
        (1, 15.99),
        (5, 25.99),
        (20, 45.99),
        (float('inf'), 45.99)  # Additional charge for weight over 20 is handled separately
    ]

    FRAGILE_MULTIPLIER = 1.5
    PRIME_DISCOUNT = 0.8

    @staticmethod
    def calculate_shipping(weight, destination, is_prime, is_fragile):
        if destination == 'domestic':
            base_cost = ShippingCalculator._calculate_base_cost(weight, ShippingCalculator.DOMESTIC_RATES)
            additional_cost = (weight - 20) * 0.50 if weight > 20 else 0
        elif destination == 'international':
            base_cost = ShippingCalculator._calculate_base_cost(weight, ShippingCalculator.INTERNATIONAL_RATES)
            additional_cost = (weight - 20) * 2.00 if weight > 20 else 0
        else:
            raise ValueError("Invalid destination: must be 'domestic' or 'international'.")

        total_cost = base_cost + additional_cost
        total_cost = ShippingCalculator._apply_fragile_multiplier(total_cost, is_fragile)
        total_cost = ShippingCalculator._apply_prime_discount(total_cost, is_prime)

        return round(total_cost, 2)

    @staticmethod
    def _calculate_base_cost(weight, rate_table):
        for limit, cost in rate_table:
            if weight < limit:
                return cost
        return 0  # This line should theoretically never be reached

    @staticmethod
    def _apply_fragile_multiplier(cost, is_fragile):
        return cost * ShippingCalculator.FRAGILE_MULTIPLIER if is_fragile else cost

    @staticmethod
    def _apply_prime_discount(cost, is_prime):
        return cost * ShippingCalculator.PRIME_DISCOUNT if is_prime else cost
