class ShippingCalculator:
    DOMESTIC_RATES = [
        (1, 5.99),
        (5, 8.99),
        (20, 12.99),
        (float('inf'), 12.99)  # Additional $0.50 per unit over 20
    ]

    INTERNATIONAL_RATES = [
        (1, 15.99),
        (5, 25.99),
        (20, 45.99),
        (float('inf'), 45.99)  # Additional $2.00 per unit over 20
    ]

    FRAGILE_MULTIPLIER = 1.5
    PRIME_DISCOUNT = 0.8

    def __init__(self, weight, destination, is_prime=False, is_fragile=False):
        self.weight = weight
        self.destination = destination
        self.is_prime = is_prime
        self.is_fragile = is_fragile

    def calculate(self):
        if self.destination == 'domestic':
            base_cost = self._calculate_base_cost(self.DOMESTIC_RATES, 0.50)
        elif self.destination == 'international':
            base_cost = self._calculate_base_cost(self.INTERNATIONAL_RATES, 2.00)
        else:
            raise ValueError("Invalid destination")

        final_cost = self._apply_modifiers(base_cost)
        return round(final_cost, 2)

    def _calculate_base_cost(self, rates, overage_rate):
        for limit, cost in rates:
            if self.weight < limit:
                if limit == float('inf'):  # Handling the overage scenario
                    return cost + (self.weight - 20) * overage_rate
                return cost
        return 0.0  # Default case, should not reach here

    def _apply_modifiers(self, cost):
        if self.is_fragile:
            cost *= self.FRAGILE_MULTIPLIER
        if self.is_prime:
            cost *= self.PRIME_DISCOUNT
        return cost

