"""
A module to calculate shipping costs based on weight, destination,
prime membership, and fragility. This module is designed to be both
maintainable and testable.
"""

from enum import Enum


class Destination(Enum):
    DOMESTIC = "domestic"
    INTERNATIONAL = "international"


def calculate_domestic_shipping(weight: float) -> float:
    """
    Calculate the base domestic shipping cost based on the given weight.
    """
    if weight < 1:
        return 5.99
    elif weight < 5:
        return 8.99
    elif weight < 20:
        return 12.99
    else:
        extra_weight = weight - 20
        return 12.99 + extra_weight * 0.50


def calculate_international_shipping(weight: float) -> float:
    """
    Calculate the base international shipping cost based on the given weight.
    """
    if weight < 1:
        return 15.99
    elif weight < 5:
        return 25.99
    elif weight < 20:
        return 45.99
    else:
        extra_weight = weight - 20
        return 45.99 + extra_weight * 2.00


def apply_fragile_surcharge(cost: float, is_fragile: bool) -> float:
    """
    If the item is fragile, apply a surcharge multiplier.
    """
    return cost * 1.5 if is_fragile else cost


def apply_prime_discount(cost: float, is_prime: bool) -> float:
    """
    If the customer is prime, apply a discount multiplier.
    """
    return cost * 0.8 if is_prime else cost


def calculate_shipping(
    weight: float,
    destination: str,
    is_prime: bool = False,
    is_fragile: bool = False,
) -> float:
    """
    Calculate the total shipping cost based on the weight, destination,
    Prime membership, and whether the item is fragile. The cost is rounded
    to two decimal places.

    :param weight: Weight of the package
    :param destination: "domestic" or "international"
    :param is_prime: Boolean indicating if the customer is a Prime member
    :param is_fragile: Boolean indicating if the package is fragile
    :return: The final shipping cost, rounded to 2 decimal places.
    """
    try:
        dest = Destination(destination.lower())
    except ValueError:
        raise ValueError(f"Invalid destination: {destination}. Valid destinations are 'domestic' and 'international'.")

    if dest == Destination.DOMESTIC:
        base_cost = calculate_domestic_shipping(weight)
    else:
        base_cost = calculate_international_shipping(weight)

    cost_after_fragile = apply_fragile_surcharge(base_cost, is_fragile)
    final_cost = apply_prime_discount(cost_after_fragile, is_prime)
    return round(final_cost, 2)


if __name__ == "__main__":
    # Unit tests
    import unittest

    class TestShippingCostCalculation(unittest.TestCase):
        def test_domestic_low_weight(self):
            self.assertEqual(calculate_shipping(0.5, "domestic"), 5.99)

        def test_domestic_middle_weight(self):
            self.assertEqual(calculate_shipping(3, "domestic"), 8.99)

        def test_domestic_high_weight(self):
            # Without prime or fragile, weight = 25 kg -> extra weight 5 -> 12.99 + 5*0.50 = 15.49
            self.assertEqual(calculate_shipping(25, "domestic"), 15.49)

        def test_international_low_weight(self):
            self.assertEqual(calculate_shipping(0.8, "international"), 15.99)

        def test_international_middle_weight(self):
            self.assertEqual(calculate_shipping(4, "international"), 25.99)

        def test_international_high_weight(self):
            # Weight = 22 kg -> extra weight 2 -> 45.99 + 2*2 = 49.99
            self.assertEqual(calculate_shipping(22, "international"), 49.99)

        def test_fragile_surcharge(self):
            # Domestic weight 3 kg cost 8.99 becomes 8.99 * 1.5 = 13.485 -> rounded to 13.49
            self.assertEqual(calculate_shipping(3, "domestic", is_fragile=True), 13.49)

        def test_prime_discount(self):
            # Domestic weight 3 kg cost 8.99 becomes 8.99 * 0.8 = 7.192 -> rounded to 7.19
            self.assertEqual(calculate_shipping(3, "domestic", is_prime=True), 7.19)

        def test_both_prime_and_fragile(self):
            # Domestic weight = 3 kg: 8.99 then fragile surcharge = 8.99 * 1.5 = 13.485
            # then prime discount = 13.485 * 0.8 = 10.788 -> rounded to 10.79
            self.assertEqual(calculate_shipping(3, "domestic", is_prime=True, is_fragile=True), 10.79)

        def test_invalid_destination(self):
            with self.assertRaises(ValueError):
                calculate_shipping(3, "mars")

    # Run tests
    unittest.main(verbosity=2)

