"""
A maintainable and testable shipping cost calculation module.
"""

class ShippingCalculator:
    def __init__(self, weight, destination, is_prime, is_fragile):
        self.weight = weight
        self.destination = destination.lower()
        self.is_prime = is_prime
        self.is_fragile = is_fragile

    def calculate(self):
        base_cost = self._calculate_base_cost()
        adjusted_cost = self._apply_adjustments(base_cost)
        return round(adjusted_cost, 2)

    def _calculate_base_cost(self):
        if self.destination == 'domestic':
            return self._calculate_domestic_cost()
        elif self.destination == 'international':
            return self._calculate_international_cost()
        else:
            raise ValueError(f"Unknown destination: {self.destination}")

    def _calculate_domestic_cost(self):
        if self.weight < 1:
            cost = 5.99
        elif self.weight < 5:
            cost = 8.99
        elif self.weight < 20:
            cost = 12.99
        else:
            additional_weight = self.weight - 20
            cost = 12.99 + additional_weight * 0.50
        return cost

    def _calculate_international_cost(self):
        if self.weight < 1:
            cost = 15.99
        elif self.weight < 5:
            cost = 25.99
        elif self.weight < 20:
            cost = 45.99
        else:
            additional_weight = self.weight - 20
            cost = 45.99 + additional_weight * 2.00
        return cost

    def _apply_adjustments(self, cost):
        if self.is_fragile:
            cost *= 1.5
        if self.is_prime:
            cost *= 0.8
        return cost

# Expose a simple functional interface
def calculate_shipping(weight, destination, is_prime, is_fragile):
    calculator = ShippingCalculator(weight, destination, is_prime, is_fragile)
    return calculator.calculate()

# Unit tests
if __name__ == "__main__":
    import unittest

    class TestShippingCalculator(unittest.TestCase):
        def test_domestic_under_1(self):
            result = calculate_shipping(0.5, 'domestic', False, False)
            self.assertAlmostEqual(result, 5.99)

        def test_domestic_between_1_and_5(self):
            result = calculate_shipping(3, 'domestic', False, False)
            self.assertAlmostEqual(result, 8.99)

        def test_domestic_between_5_and_20(self):
            result = calculate_shipping(10, 'domestic', False, False)
            self.assertAlmostEqual(result, 12.99)

        def test_domestic_over_20(self):
            result = calculate_shipping(25, 'domestic', False, False)
            expected = 12.99 + (25 - 20) * 0.50
            self.assertAlmostEqual(result, expected)

        def test_international_under_1(self):
            result = calculate_shipping(0.5, 'international', False, False)
            self.assertAlmostEqual(result, 15.99)

        def test_international_between_1_and_5(self):
            result = calculate_shipping(3, 'international', False, False)
            self.assertAlmostEqual(result, 25.99)

        def test_international_between_5_and_20(self):
            result = calculate_shipping(10, 'international', False, False)
            self.assertAlmostEqual(result, 45.99)

        def test_international_over_20(self):
            result = calculate_shipping(25, 'international', False, False)
            expected = 45.99 + (25 - 20) * 2.00
            self.assertAlmostEqual(result, expected)

        def test_fragile_adjustment(self):
            # domestic, weight under 1, fragile increases cost by 1.5
            base = 5.99
            expected = base * 1.5
            result = calculate_shipping(0.5, 'domestic', False, True)
            self.assertAlmostEqual(result, expected, places=2)

        def test_prime_adjustment(self):
            # domestic, weight under 1, prime decreases cost by 20%
            base = 5.99
            expected = base * 0.8
            result = calculate_shipping(0.5, 'domestic', True, False)
            self.assertAlmostEqual(result, expected, places=2)

        def test_both_adjustments(self):
            # domestic, weight under 1, both adjustments applied: first fragile then prime.
            base = 5.99
            expected = base * 1.5 * 0.8
            result = calculate_shipping(0.5, 'domestic', True, True)
            self.assertAlmostEqual(result, expected, places=2)

        def test_invalid_destination(self):
            with self.assertRaises(ValueError):
                calculate_shipping(1, 'unknown', False, False)

    unittest.main()

