"""
Module: shipping_calculator

Provides functionality to calculate shipping costs based on weight, destination,
and additional package attributes such as fragility and membership status.
"""

def calculate_base_cost(weight: float, destination: str) -> float:
    """
    Calculate the base shipping cost based on weight and destination.

    Parameters:
        weight (float): The weight of the package in pounds.
        destination (str): The destination for shipping ('domestic' or 'international').

    Returns:
        float: The base shipping cost.

    Raises:
        ValueError: If the destination is not recognized.
    """
    if destination == 'domestic':
        if weight < 1:
            return 5.99
        elif weight < 5:
            return 8.99
        elif weight < 20:
            return 12.99
        else:
            return 12.99 + (weight - 20) * 0.50
    elif destination == 'international':
        if weight < 1:
            return 15.99
        elif weight < 5:
            return 25.99
        elif weight < 20:
            return 45.99
        else:
            return 45.99 + (weight - 20) * 2.00
    else:
        raise ValueError("Invalid destination provided. Must be 'domestic' or 'international'.")


def apply_modifiers(cost: float, is_fragile: bool, is_prime: bool) -> float:
    """
    Adjust the cost according to package attributes.

    Parameters:
        cost (float): The base cost to modify.
        is_fragile (bool): Flag indicating if the package is fragile.
        is_prime (bool): Flag indicating if the order qualifies for prime discount.

    Returns:
        float: The final cost after applying modifiers.
    """
    if is_fragile:
        cost *= 1.5
    if is_prime:
        cost *= 0.8
    return cost


def calculate_shipping(weight: float, destination: str, is_prime: bool, is_fragile: bool) -> float:
