def calculate_domestic_base_cost(weight):
    """Calculate the base shipping cost for domestic orders based on weight."""
    if weight < 1:
        return 5.99
    elif weight < 5:
        return 8.99
    elif weight < 20:
        return 12.99
    else:
        additional_weight = weight - 20
        return 12.99 + additional_weight * 0.50


def calculate_international_base_cost(weight):
    """Calculate the base shipping cost for international orders based on weight."""
    if weight < 1:
        return 15.99
    elif weight < 5:
        return 25.99
    elif weight < 20:
        return 45.99
    else:
        additional_weight = weight - 20
        return 45.99 + additional_weight * 2.00


def apply_additional_charges(base_cost, is_fragile, is_prime):
    """
    Apply additional cost multipliers for fragile items and prime discount.

    Fragile items incur a 50% surcharge.
    Prime orders receive a 20% discount.
    """
    if is_fragile:
        base_cost *= 1.5
    if is_prime:
        base_cost *= 0.8
    return base_cost


def calculate_shipping(weight, destination, is_prime, is_fragile):
    """
    Calculate the total shipping cost based on weight, destination,
    and attributes like prime eligibility and fragility.

    Raises:
        ValueError: If the destination is not 'domestic' or 'international'.
    """
    destination = destination.lower()  # Normalize input

    if destination == 'domestic':
        base_cost = calculate_domestic_base_cost(weight)
    elif destination == 'international':
        base_cost = calculate_international_base_cost(weight)
    else:
        raise ValueError("Invalid destination. Must be 'domestic' or 'international'.")

    final_cost = apply_additional_charges(base_cost, is_fragile, is_prime)
    return round(final_cost, 2)


