            return Decimal('12.99') + (excess_weight * Decimal('0.50'))


class InternationalShippingCalculator(ShippingRateCalculator):
    def calculate_base_cost(self, weight: float) -> Decimal:
        if weight < 1:
            return Decimal('15.99')
        elif weight < 5:
            return Decimal('25.99')
        elif weight < 20:
            return Decimal('45.99')
        else:
